def constant_time_compare(a, b):
    """Constant-time string comparison to prevent timing attacks."""
    if len(a) != len(b):
        return False
    result = 0
    for x, y in zip(a.encode() if isinstance(a, str) else a,
                     b.encode() if isinstance(b, str) else b):
        result |= x ^ y
    return result == 0


