def decode_websocket_frame(data):
    """Decode a WebSocket frame per RFC 6455 with size validation."""
    if len(data) < 2:
        return None, None, False

    first_byte = data[0]
    second_byte = data[1]

    fin = (first_byte >> 7) & 1
    opcode = first_byte & 0x0F
    masked = (second_byte >> 7) & 1
    payload_length = second_byte & 0x7F

    # Clients MUST mask frames sent to server (RFC 6455 Section 5.1)
    if not masked:
        print("Rejected unmasked frame from client")
        return None, opcode, False

    offset = 2

    if payload_length == 126:
        if len(data) < 4:
            return None, None, False
        payload_length = struct.unpack("!H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None, None, False
        payload_length = struct.unpack("!Q", data[2:10])[0]
        offset = 10

    # Enforce maximum frame size to prevent memory exhaustion
    if payload_length > MAX_FRAME_SIZE:
        print("Frame too large:", payload_length)
        return None, opcode, False

    if len(data) < offset + 4 + payload_length:
        return None, None, False

    masking_key = data[offset:offset + 4]
    offset += 4

    payload = bytearray(data[offset:offset + payload_length])
    for i in range(payload_length):
        payload[i] ^= masking_key[i % 4]

    return bytes(payload), opcode, True


def encode_websocket_frame(data, opcode=0x01):
    """Encode data into a WebSocket frame. Server frames are NOT masked (RFC 6455)."""
    if isinstance(data, str):
        data = data.encode("utf-8")

    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN + opcode

    length = len(data)
    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack("!H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack("!Q", length))

    frame.extend(data)
    return bytes(frame)


