def sanitize_string(s, max_length=128):
    """Sanitize a string input."""
    if not isinstance(s, str):
        return ""
    # Truncate to max length
    s = s[:max_length]
    # Remove control characters
    return "".join(c for c in s if ord(c) >= 32 or c in ("\n", "\r", "\t"))


def handle_command(command_data, client_id):
    """Process a validated JSON command and return response."""
