def gc_free_mem():
    """Get free memory safely."""
    try:
        import gc
        gc.collect()
        return gc.mem_free()
    except Exception:
        return 0


class WebSocketClient:
    """Represents a connected WebSocket client."""

    def __init__(self, socket, address):
        self.socket = socket
        self.address = address
        self.client_id = "{}:{}".format(address[0], address[1])
        self.authenticated = False
        self.last_activity = time.time()
        self.last_ping = time.time()

    def is_timed_out(self):
        return (time.time() - self.last_activity) > CONNECTION_TIMEOUT

    def needs_ping(self):
        return (time.time() - self.last_ping) > PING_INTERVAL


class WebSocketServer:
    """Secure WebSocket server for ESP32 IoT control."""

    def __init__(self, host, port):
        self.host = host
        self.port = port
        self.server_socket = None
        self.clients = []
        self.running = False

    def start(self):
        """Start the WebSocket server."""
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
