    def maintenance(self):
        """Perform periodic maintenance tasks."""
        for client in self.clients[:]:
            # Check for timed-out clients
            if client.is_timed_out():
                print("Client timed out:", client.client_id)
                self.disconnect_client(client, 1001, "Timeout")
                continue

            # Send periodic pings
            if client.needs_ping():
                send_ping(client.socket)
                client.last_ping = time.time()

    def run(self):
        """Main server loop."""
        self.start()
        last_maintenance = time.time()

        try:
            while self.running:
                # Accept new connections
                self.accept_new_client()

                # Handle existing clients
                for client in self.clients[:]:
                    self.handle_client_data(client)

                # Periodic maintenance
                if time.time() - last_maintenance > 10:
                    self.maintenance()
                    last_maintenance = time.time()

                # Small delay to prevent CPU hogging
                time.sleep_ms(10)

        except KeyboardInterrupt:
            print("\nShutting down server...")
        finally:
            self.shutdown()

    def shutdown(self):
        """Gracefully shut down the server."""
        self.running = False
        for client in self.clients[:]:
            self.disconnect_client(client, 1001, "Server shutting down")
        if self.server_socket:
            self.server_socket.close()
        print("Server stopped.")


